package main

import (
	"fmt"
	"strconv"
)

// isNonDecreasing checks if the sequence of 7 digits is non-decreasing.
func isNonDecreasing(sequence []int) bool {
	if len(sequence) != 7 {
		return false
	}
	for i := 0; i < 6; i++ {
		if sequence[i] > sequence[i+1] {
			return false
		}
	}
	return true
}

// checkNumber determines if a single number x is a "good" integer.
func checkNumber(x int64, directions string) bool {
	// 1. Format x to 16 digits string, padded with leading zeros.
	s := strconv.FormatInt(x, 10)
	paddedS := fmt.Sprintf("%016s", s)

	// 2. Populate the 4x4 grid.
	grid := [4][4]int{}
	k := 0
	for i := 0; i < 4; i++ {
		for j := 0; j < 4; j++ {
			// Since k will go from 0 to 15, we rely on paddedS being exactly 16 characters.
			digit, _ := strconv.Atoi(string(paddedS[k]))
			grid[i][j] = digit
			k++
		}
	}

	// 3. Determine the path.
	rCurr, cCurr := 0, 0
	pathPositions := make([][2]int, 0, 7) 

	// The starting cell (0, 0) is the first element of the sequence.
	pathPositions = append(pathPositions, [2]int{0, 0})

	// Apply 6 directions
	for _, d := range directions {
		if d == 'D' {
			rCurr++
		} else if d == 'R' {
			cCurr++
		}

        // The problem implies movement stays within the 4x4 grid.
        // We only record the position if it is within bounds [0, 3].
        if rCurr >= 0 && rCurr < 4 && cCurr >= 0 && cCurr < 4 {
		    pathPositions = append(pathPositions, [2]int{rCurr, cCurr})
        }
	}

	// 4. Collect the sequence.
	sequence := make([]int, 0, 7)
	for _, pos := range pathPositions {
		r, c := pos[0], pos[1]
		sequence = append(sequence, grid[r][c])
	}

	// 5. Check condition.
	return isNonDecreasing(sequence)
}

func solve(l int64, r int64, directions string) int64 {
	count := int64(0)
	for x := l; x <= r; x++ {
		if checkNumber(x, directions) {
			count++
		}
	}
	return count
}
